// Valida o payload vindo do backend FastAPI antes de chamar Claude.
// O backend ja sanitiza, mas validamos novamente para defesa em profundidade.

const item = $input.first();
const raw = item.json?.body ?? item.json ?? {};
const now = new Date().toISOString();

const texto_documento = String(raw.texto_documento || '').trim();
const campos_novos = raw.campos_novos || {};
const nome = campos_novos.nome ? String(campos_novos.nome).trim() : null;
const numero_processo = campos_novos.numero_processo ? String(campos_novos.numero_processo).trim() : null;
const valor_causa = campos_novos.valor_causa ? String(campos_novos.valor_causa).trim() : null;

const erros = [];
if (!texto_documento) erros.push('texto_documento obrigatorio');
if (!nome && !numero_processo && !valor_causa) erros.push('pelo menos um campo novo deve ser informado');
if (texto_documento.length > 200000) erros.push('texto_documento excede 200000 caracteres');

if (erros.length > 0) {
  return [{ json: { status: 'erro_validacao', mensagem: 'Falha de validacao no workflow.', erros, recebido_em: now } }];
}

return [{ json: { status: 'entrada_validada', contexto: { texto_documento, campos_novos: { nome, numero_processo, valor_causa } }, recebido_em: now } }];

// Chama Claude em modo extracao (temperatura 0.0) para identificar pares
// antigo<->novo no texto. Sem criatividade, sem alucinacao.
//
// Resposta esperada (JSON estrito):
// {
//   "substituicoes": [{"campo":"nome","antigo":"...","novo":"...","ocorrencias_esperadas":N}, ...],
//   "campos_ausentes": ["valor_causa"]
// }

const readEnv = (key, fb = '') => {
  try {
    if (typeof $vars !== 'undefined' && $vars && $vars[key]) return String($vars[key]).trim();
    return ($env && $env[key]) ? String($env[key]).trim() : (process.env[key] || fb);
  } catch { return process.env[key] || fb; }
};

const stripFences = s => {
  const cleaned = String(s || '').trim().replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
  const first = cleaned.indexOf('{');
  const last = cleaned.lastIndexOf('}');
  if (first === -1 || last === -1 || last < first) return cleaned;
  return cleaned.slice(first, last + 1);
};

const envelope = $input.first().json;
if (envelope.status === 'erro_validacao') return [{ json: envelope }];

const { contexto, recebido_em } = envelope;
const { texto_documento, campos_novos } = contexto;

const ANTHROPIC_KEY = readEnv('ANTHROPIC_API_KEY') || readEnv('CLAUDE_API_KEY');
const CLAUDE_MODEL = readEnv('CLAUDE_MODEL') || 'claude-sonnet-4-6';
const BASE_URL = (readEnv('ANTHROPIC_BASE_URL') || 'https://api.anthropic.com').replace(/\/$/, '');
const API_VERSION = readEnv('ANTHROPIC_VERSION') || '2023-06-01';
const MAX_TOKENS = 1500;
const TEMPERATURE = 0.0;
const TIMEOUT_MS = Math.max(10000, parseInt(readEnv('CLAUDE_TIMEOUT_MS', '60000'), 10) || 60000);

const SYSTEM_PROMPT = `Voce eh um agente de edicao ciruurgica de documentos juridicos brasileiros.
Recebera o texto extraido de uma contestacao em .docx e ate 3 campos novos
(nome, numero_processo, valor_causa). Sua tarefa eh identificar a OCORRENCIA
PRINCIPAL de cada campo no texto antigo e listar pares antigo<->novo.

Responda SOMENTE com JSON valido (sem markdown, sem codeblock), com este schema:
{
  "substituicoes": [
    {"campo": "nome",            "antigo": "...", "novo": "...", "ocorrencias_esperadas": N},
    {"campo": "numero_processo", "antigo": "...", "novo": "...", "ocorrencias_esperadas": N},
    {"campo": "valor_causa",     "antigo": "...", "novo": "...", "ocorrencias_esperadas": N}
  ],
  "campos_ausentes": ["valor_causa"]
}

REGRAS RIGOROSAS:
- Se um campo NOVO foi pedido mas NAO existe no texto, inclua-o em
  "campos_ausentes" e NAO crie substituicao para ele.
- "antigo" deve ser uma string EXATA do texto (case-sensitive, espacos
  exatos, sem reformatar).
- NAO invente ocorrencias. NAO faca outras alteracoes alem das pedidas.
- "ocorrencias_esperadas" eh o numero EXATO de vezes que "antigo" aparece
  no texto. Conte com cuidado — o backend abortara se divergir.
- Para o campo "nome": identifique o nome da parte (Reclamado/Reu/Contestante).
  Use o nome COMPLETO como aparece ("Janaina Pereira da Silva Matos", nao
  apenas "Janaina").
- Para "numero_processo": identifique no formato CNJ
  (XXXXXXX-XX.XXXX.X.XX.XXXX). Capture o numero EXATO.
- Para "valor_causa": identifique valor monetario brasileiro (R$ X.XXX,XX)
  tipicamente apos rotulos como "valor da causa", "valor atribuido".
- Se houver MULTIPLAS ocorrencias do antigo, conte todas e liste apenas UMA
  entrada com o total em ocorrencias_esperadas (a substituicao sera global).`;

const USER_MSG = `TEXTO_DOCUMENTO:\n${texto_documento}\n\nCAMPOS_NOVOS:\n${JSON.stringify(campos_novos, null, 2)}`;

function buildFallback(motivo) {
  return {
    substituicoes: [],
    campos_ausentes: Object.keys(campos_novos).filter(k => campos_novos[k]),
    _fallback_motivo: motivo
  };
}

let resposta = null;
let provider = 'fallback_local';
let apiError = null;

if (!ANTHROPIC_KEY) {
  apiError = 'ANTHROPIC_API_KEY nao configurada';
} else {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), TIMEOUT_MS);
  try {
    const resp = await fetch(`${BASE_URL}/v1/messages`, {
      method: 'POST',
      headers: {
        'x-api-key': ANTHROPIC_KEY,
        'anthropic-version': API_VERSION,
        'content-type': 'application/json',
        'anthropic-beta': 'prompt-caching-2024-07-31'
      },
      body: JSON.stringify({
        model: CLAUDE_MODEL,
        max_tokens: MAX_TOKENS,
        temperature: TEMPERATURE,
        system: [{ type: 'text', text: SYSTEM_PROMPT, cache_control: { type: 'ephemeral' } }],
        messages: [{ role: 'user', content: USER_MSG }]
      }),
      signal: controller.signal
    });
    if (!resp.ok) {
      const e = await resp.text().catch(() => '');
      throw new Error(`HTTP ${resp.status}: ${e.slice(0, 200)}`);
    }
    const payload = await resp.json();
    const raw = (payload.content || []).filter(b => b.type === 'text').map(b => b.text).join('').trim();
    if (!raw) throw new Error('resposta_ia_sem_conteudo');
    try {
      resposta = JSON.parse(stripFences(raw));
      provider = 'claude';
    } catch (e) {
      throw new Error(`json_parse_error: ${e.message}`);
    }
  } catch (e) {
    apiError = e.name === 'AbortError' ? `timeout_${TIMEOUT_MS}ms` : e.message;
  } finally {
    clearTimeout(timer);
  }
}

if (!resposta) resposta = buildFallback(apiError || 'sem_chave');

// Sanitiza estrutura — garante shape exato esperado pelo backend.
const substituicoes = Array.isArray(resposta.substituicoes) ? resposta.substituicoes : [];
const campos_ausentes = Array.isArray(resposta.campos_ausentes) ? resposta.campos_ausentes : [];

const substituicoes_validas = substituicoes
  .filter(s => s && typeof s === 'object' && s.campo && s.antigo && s.novo && Number.isInteger(s.ocorrencias_esperadas) && s.ocorrencias_esperadas >= 1)
  .map(s => ({
    campo: String(s.campo),
    antigo: String(s.antigo),
    novo: String(s.novo),
    ocorrencias_esperadas: parseInt(s.ocorrencias_esperadas, 10)
  }));

return [{
  json: {
    status: 'ok',
    substituicoes: substituicoes_validas,
    campos_ausentes: campos_ausentes.map(c => String(c)),
    engine_ia: {
      provider,
      model: provider === 'claude' ? CLAUDE_MODEL : 'fallback_local',
      temperature: TEMPERATURE,
      max_tokens: MAX_TOKENS,
      api_error: apiError
    },
    recebido_em,
    processado_em: new Date().toISOString()
  }
}];
